import React from 'react';

export default function HistoryList({ title, items, renderItem, emptyText }) {
  return (
    <section className="history-panel">
      <div className="history-header">
        <h3>{title}</h3>
      </div>
      {items.length ? (
        <div className="history-grid">
          {items.map((item) => (
            <button type="button" className="history-card" key={item.id} onClick={() => renderItem(item)}>
              <div className="history-card-title">{item.title}</div>
              <div className="history-card-meta">{new Date(item.createdAt).toLocaleString()}</div>
            </button>
          ))}
        </div>
      ) : (
        <div className="history-empty">{emptyText}</div>
      )}
    </section>
  );
}
